class RecentCounter {
    int[] requests;
    int count;

    public RecentCounter() {
        requests = new int[1000000];
        count = 0;
    }

    public int ping(int t) {
        if (t > count) {
            requests[t - 1]++;
            count = t;
        }
        return count;
    }
}
```

